  const removeDuplicateFiles = (files) => {
    const seen = new Set();
    const uniqueFiles = [];

    for (const file of files) {
      // Create multiple keys for deduplication
      const keys = [
        file.uniqueId,
        `${file.name}-${file.source}-${file.uploadBatch}`,
        `${file.name}-${file.uploadedAt}`,
        `${file.name}-${file.source}-${new Date(file.uploadedAt).getTime()}`
      ].filter(Boolean);

      let isDuplicate = false;
      for (const key of keys) {
        if (seen.has(key)) {
          isDuplicate = true;
          console.log('🔍 Duplicate detected with key:', key, 'for file:', file.name);
          break;
        }
      }

      if (!isDuplicate) {
        keys.forEach(key => seen.add(key));
        uniqueFiles.push(file);
      }
    }

    console.log('🧹 Removed duplicates:', files.length - uniqueFiles.length, 'files');
    return uniqueFiles;
  };

