  useEffect(() => {
    window.saveFileToSession = saveFile;
    window.refreshSavedFiles = refreshFiles;
    window.cleanDuplicateFiles = cleanDuplicates;

    return () => {
      delete window.saveFileToSession;
      delete window.refreshSavedFiles;
      delete window.cleanDuplicateFiles;
    };
  }, [user, sessionId]);

